To write unit tests for the `flatten_dict` function using `pytest`, we need to cover the happy path, edge cases, and error cases. Below is a set of tests that should provide good coverage:

```python
import pytest

def flatten_dict(d: dict, parent_key: str = '', sep: str = '.') -> dict:
    items = []
    for k, v in d.items():
        new_key = f'{parent_key}{sep}{k}' if parent_key else k
        if isinstance(v, dict):
            items.extend(flatten_dict(v, new_key, sep).items())
        else:
            items.append((new_key, v))
    return dict(items)

def test_flatten_dict_happy_path():
    input_dict = {
        'a': 1,
        'b': {
            'c': 2,
            'd': {
                'e': 3
            }
        }
    }
    expected_output = {
        'a': 1,
        'b.c': 2,
        'b.d.e': 3
    }
    assert flatten_dict(input_dict) == expected_output

def test_flatten_dict_with_custom_separator():
    input_dict = {
        'a': 1,
        'b': {
            'c': 2,
            'd': {
                'e': 3
            }
        }
    }
    expected_output = {
        'a': 1,
        'b_c': 2,
        'b_d_e': 3
    }
    assert flatten_dict(input_dict, sep='_') == expected_output

def test_flatten_dict_with_parent_key():
    input_dict = {
        'a': 1,
        'b': {
            'c': 2,
            'd': {
                'e': 3
            }
        }
    }
    expected_output = {
        'x.a': 1,
        'x.b.c': 2,
        'x.b.d.e': 3
    }
    assert flatten_dict(input_dict, parent_key='x') == expected_output

def test_flatten_dict_with_empty_input():
    input_dict = {}
    expected_output = {}
    assert flatten_dict(input_dict) == expected_output

def test_flatten_dict_with_nested_empty_dict():
    input_dict = {
        'a': 1,
        'b': {
            'c': {},
            'd': {
                'e': 3
            }
        }
    }
    expected_output = {
        'a': 1,
        'b.d.e': 3
    }
    assert flatten_dict(input_dict) == expected_output

def test_flatten_dict_with_non_dict_value():
    input_dict = {
        'a': 1,
        'b': [1, 2, 3],
        'c': {
            'd': 4
        }
    }
    expected_output = {
        'a': 1,
        'b': [1, 2, 3],
        'c.d': 4
    }
    assert flatten_dict(input_dict) == expected_output

def test_flatten_dict_with_non_string_keys():
    input_dict = {
        1: 'a',
        'b': {
            2: 'c',
            'd': {
                3: 'e'
            }
        }
    }
    expected_output = {
        '1': 'a',
        'b.2': 'c',
        'b.d.3': 'e'
    }
    assert flatten_dict(input_dict) == expected_output

def test_flatten_dict_with_non_dict_input():
    with pytest.raises(AttributeError):
        flatten_dict([])

def test_flatten_dict_with_non_string_parent_key():
    input_dict = {
        'a': 1,
        'b': {
            'c': 2
        }
    }
    with pytest.raises(TypeError):
        flatten_dict(input_dict, parent_key=123)

def test_flatten_dict_with_non_string_separator():
    input_dict = {
        'a': 1,
        'b': {
            'c': 2
        }
    }
    with pytest.raises(TypeError):
        flatten_dict(input_dict, sep=123)

if __name__ == "__main__":
    pytest.main()
```

